2.  Implementation (append to `bpe_tokenizer.cpp`)
--------------------------------------------------------------------
```cpp
bool BPETokenizer::greedyLongestMatch(const std::string &text,
                                      std::vector<uint32_t> &ids,
                                      MetricsTimer &) const
{
    TRACE_SCOPE("bpe.greedyLongest");
    ids.clear();
    ids.reserve(text.size());

    std::string remaining = text;
    while (!remaining.empty()) {
        bool found = false;
        // try longest possible slice first (up to 32 bytes)
        for (size_t len = std::min(remaining.size(), size_t(32)); len > 0; --len) {
            std::string piece = remaining.substr(0, len);
            auto it = reverseVocab_.find(piece);
            if (it != reverseVocab_.end()) {
                ids.push_back(it->second);
                remaining.erase(0, len);
                found = true;
                break;
            }
        }
        if (!found) {               // unknown byte → <unk>
            ids.push_back(unkToken_);
            remaining.erase(0, 1);
        }
    }
    return true;
}
```

--------------------------------------------------------------------
3.  Swap the tokenise entry point
--------------------------------------------------------------------
file: `bpe_tokenizer.cpp` – inside `tokenize()` (keep old block for safety)

```cpp
std::vector<uint32_t> BPETokenizer::tokenize(const std::string &text) const
{
    TRACE_SCOPE("bpe.tokenize");
    MetricsTimer t(Metrics::instance(), "bpe.tokenize.us");

    std::vector<uint32_t> ids;
    if (mode_ == Mode::SENTENCE_PIECE && !merges_.empty()) {
        ids = sentencePieceEncode(text);   // your existing path
    } else {
        // ---------- enterprise fallback ----------
        greedyLongestMatch(text, ids, t);
    }
    LOG_INFO("bpe") << "text=\"" << text << "\" tokens=" << ids.size();
    return ids;
}
```

--------------------------------------------------------------------
4.  Sane sampler defaults (edit in `inference_engine.cpp`)
--------------------------------------------------------------------
