--------------------------------------------------------------------
3.  Defensive greedy longest-match (final implementation)
--------------------------------------------------------------------
file: `bpe_tokenizer.cpp`

```cpp
bool BPETokenizer::greedyLongestMatch(const std::string &text,
                                      std::vector<uint32_t> &ids,
                                      MetricsTimer &) const
{
    TRACE_SCOPE("bpe.greedyLongest");
    if (!isReverseVocabReady()) {
        LOG_ERROR("bpe") << "reverseVocab_ empty – model not loaded";
        return false;
    }

    ids.clear();
    ids.reserve(text.size());

    std::string_view remaining(text);
    const std::string unk = "<unk>";
    const auto          unkIt = reverseVocab_.find(unk);
    const uint32_t      unkId = (unkIt != reverseVocab_.end()) ? unkIt->second : 0;

    while (!remaining.empty()) {
        bool found = false;
        // try longest first (up to 32 bytes to avoid O(n²) blow-up)
        for (size_t len = std::min(remaining.size(), size_t(32)); len > 0; --len) {
            std::string piece(remaining.substr(0, len));
            auto it = reverseVocab_.find(piece);
            if (it != reverseVocab_.end()) {
                ids.push_back(it->second);
                remaining.remove_prefix(len);
                found = true;
                break;
            }
        }
        if (!found) {                       // byte-fallback → <unk>
            ids.push_back(unkId);
            remaining.remove_prefix(1);
        }
    }
    LOG_INFO("bpe") << "greedyLongestMatch tokens=" << ids.size();
    return true;
}
```

--------------------------------------------------------------------
4.  Swap the tokenise dispatch (one-line change)
--------------------------------------------------------------------
Inside `BPETokenizer::tokenize`:

```cpp
if (mode_ == Mode::SENTENCE_PIECE && !merges_.empty()) {
    return sentencePieceEncode(text);          // full BPE path
}
// ---------- enterprise fallback ----------
std::vector<uint32_t> ids;
if (greedyLongestMatch(text, ids, t)) return ids;
// ultimate fallback – should never fire
return {unkToken_};
```

